// Prepare raw email data for AI extraction (v2.1)
// Fix: handle Gmail object-type header values (From/To returned as objects, not strings)
// Robust from_email fix + full metadata extraction

const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;

  // Helper: resolve a value that might be string, object, or array to a readable string
  function resolveValue(val) {
    if (typeof val === 'string') return val;
    if (val && typeof val === 'object') {
      if (val.text && typeof val.text === 'string') return val.text;
      if (Array.isArray(val.value) && val.value[0]) {
        const parts = val.value.map(v => v.address ? (v.name ? v.name + ' <' + v.address + '>' : v.address) : '');
        return parts.filter(Boolean).join(', ');
      }
      if (val.address) return val.name ? val.name + ' <' + val.address + '>' : val.address;
      if (Array.isArray(val)) {
        return val.map(v => resolveValue(v)).filter(Boolean).join(', ');
      }
      try { const j = JSON.stringify(val); if (j !== '{}') return j; } catch(e) {}
    }
    return '';
  }

  // Helper: extract any email header by name (works across all Gmail data formats)
  function getHeader(name) {
    // Path 1: payload.headers array (simple=false standard)
    if (d.payload && d.payload.headers && Array.isArray(d.payload.headers)) {
      const h = d.payload.headers.find(h => h.name && h.name.toLowerCase() === name.toLowerCase());
      if (h && h.value) return h.value;
    }
    // Path 2: top-level capitalized (simple=true or n8n processed)
    const capKey = name.charAt(0).toUpperCase() + name.slice(1);
    if (d[capKey]) return resolveValue(d[capKey]);
    // Path 3: top-level lowercase
    if (d[name.toLowerCase()]) return resolveValue(d[name.toLowerCase()]);
    // Path 4: headers object (some n8n versions)
    if (d.headers && typeof d.headers === 'object' && !Array.isArray(d.headers)) {
      const val = d.headers[name] || d.headers[name.toLowerCase()];
      if (val) return resolveValue(val);
    }
    return '';
  }

  // Detect source
  const isEmail = d.snippet !== undefined || d.threadId !== undefined || d.Subject !== undefined || d.From !== undefined || (d.payload && d.payload.headers);
  const source = isEmail ? 'email' : 'webhook';

  // Extract subject
  const subject = isEmail
    ? (getHeader('Subject') || '')
    : (d.body?.subject || d.subject || '');

  // LOOP GUARD: Skip notification emails sent by this pipeline
  if (isEmail && (subject.includes('EMI Pipeline:') || subject.includes('EMI Pipeline —'))) {
    continue;
  }

  // Extract body
  let body = '';
  if (isEmail) {
    body = d.textPlain || d.text || d.snippet || d.textHtml || '';
    if ((!body || body.length < 50) && d.payload && d.payload.parts) {
      for (const part of d.payload.parts) {
        if (part.mimeType === 'text/plain' && part.body && part.body.data) {
          try { body = Buffer.from(part.body.data, 'base64').toString('utf-8'); } catch(e) {}
          break;
        }
      }
    }
    if ((!body || body.length < 50) && d.payload && d.payload.body && d.payload.body.data) {
      try { body = Buffer.from(d.payload.body.data, 'base64').toString('utf-8'); } catch(e) {}
    }
    body = body.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
  } else {
    const raw = d.body?.body || d.bodyPreview || d.body || '';
    body = typeof raw === 'string' ? raw : '';
  }

  // Extract from (robust multi-path)
  let from = '';
  if (isEmail) {
    let rawFrom = getHeader('From');
    if (!rawFrom) {
      for (const [key, val] of Object.entries(d)) {
        if (key.toLowerCase().includes('from') && typeof val === 'string' && val.includes('@')) {
          rawFrom = val; break;
        }
      }
    }
    if (typeof rawFrom === 'string' && rawFrom) {
      const m = rawFrom.match(/<([^>]+)>/);
      from = m ? m[1] : rawFrom.trim();
    }
  } else {
    from = d.body?.from || d.from || '';
  }

  // METADATA EXTRACTION (email path only)
  const to_email = isEmail ? getHeader('To') : '';
  const cc_emails = isEmail ? getHeader('Cc') : '';
  const reply_to = isEmail ? getHeader('Reply-To') : '';
  const email_date = isEmail ? getHeader('Date') : '';
  const message_id = d.id || (isEmail ? getHeader('Message-ID') : '') || '';
  const thread_id = d.threadId || '';

  // Attachment detection (recursive MIME part scan)
  let has_attachments = false;
  const attachment_names = [];
  function scanParts(parts) {
    if (!Array.isArray(parts)) return;
    for (const part of parts) {
      if (part.filename && part.filename.length > 0) {
        has_attachments = true;
        attachment_names.push(part.filename);
      }
      if (part.parts) scanParts(part.parts);
    }
  }
  if (d.payload && d.payload.parts) scanParts(d.payload.parts);

  // Build AI prompt
  const prompt = `You are an email parser for Wave Money's EMI (Electronic Money Issuer) salary disbursement pipeline in Myanmar.

Analyze this email and extract structured data.

EMAIL SUBJECT: ${subject}
EMAIL BODY: ${body}
FROM: ${from}

Return a JSON object with these exact fields:
{
  "is_disbursement": true or false (is this a salary/EMI/disbursement/OTC request?),
  "company": "company name requesting disbursement",
  "amount": number (total amount in MMK, 0 if not found),
  "type": "SalaryToOTC" if OTC or over-the-counter is mentioned, otherwise "SalaryToMA",
  "approvers": [{"name": "person name", "role": "their title/role", "status": "Approved"}],
  "body_preview": "first 200 characters of the email body"
}

IMPORTANT: Return ONLY the JSON object, no explanation or markdown.`;

  results.push({
    json: {
      _source: source,
      from_email: from,
      original_subject: subject,
      prompt: prompt,
      to_email: to_email,
      cc_emails: cc_emails,
      reply_to: reply_to,
      email_date: email_date,
      message_id: message_id,
      thread_id: thread_id,
      has_attachments: has_attachments,
      attachment_names: attachment_names,
      attachment_count: attachment_names.length,
    }
  });
}

return results;

// Parse AI response (Groq/OpenAI format), validate authority matrix, generate dashboard URL
// v2: passes email metadata through to ticket + output

const items = $input.all();
const results = [];

// Retrieve metadata from Prepare node (HTTP Request replaces item data)
const prepData = $('Prepare for AI').first().json;
const source = prepData._source;
const from_email = prepData.from_email;
const original_subject = prepData.original_subject;
const to_email = prepData.to_email || '';
const cc_emails = prepData.cc_emails || '';
const reply_to = prepData.reply_to || '';
const email_date = prepData.email_date || '';
const message_id = prepData.message_id || '';
const thread_id = prepData.thread_id || '';
const has_attachments = prepData.has_attachments || false;
const attachment_names = prepData.attachment_names || [];
const attachment_count = prepData.attachment_count || 0;

for (const item of items) {
  const d = item.json;

  // Extract AI response text — Groq/OpenAI format
  let aiText = '';
  if (d.choices && d.choices[0]) {
    aiText = d.choices[0].message.content || '';
  }

  // Parse JSON from AI response
  let parsed = {};
  try {
    parsed = JSON.parse(aiText);
  } catch (e) {
    // Fallback: try extracting from markdown code block
    const jsonMatch = aiText.match(/```json?\s*([\s\S]*?)```/);
    if (jsonMatch) {
      try { parsed = JSON.parse(jsonMatch[1]); } catch (e2) {}
    }
  }

  // AI-powered keyword filter: skip non-disbursement emails
  if (!parsed.is_disbursement) {
    return [];
  }

  // AUTHORITY MATRIX CHECK
  const required = ['Sales HOD', 'Finance Manager'];
  const matrixResults = required.map(req => {
    const found = (parsed.approvers || []).find(a =>
      a.role.toLowerCase().includes(req.toLowerCase())
    );
    return {
      requiredRole: req,
      found: !!found,
      foundName: found ? found.name : 'MISSING',
    };
  });
  const matrixComplete = matrixResults.every(m => m.found);

  // SCENARIO DETECTION
  let scenario = 'NORMAL';
  if (!matrixComplete) {
    scenario = 'MISSING_APPROVAL';
  }

  // BUILD TICKET PAYLOAD (includes metadata)
  const ticket = {
    company: parsed.company || 'Unknown Company',
    type: parsed.type || 'SalaryToMA',
    amount_requested: parsed.amount || 0,
    amount_on_bank_slip: parsed.amount || 0,
    currency: 'MMK',
    approvals: parsed.approvers || [],
    required_approvals: required,
    body_preview: parsed.body_preview || '',
    parsed_at: new Date().toISOString(),
    scenario,
    approval_matrix_complete: matrixComplete,
    ai_parsed: true,
    from_email: from_email,
    to_email: to_email,
    cc_emails: cc_emails,
    reply_to: reply_to,
    email_date: email_date,
    message_id: message_id,
    thread_id: thread_id,
    has_attachments: has_attachments,
    attachment_names: attachment_names,
    attachment_count: attachment_count,
  };

  // GENERATE DASHBOARD URL
  const encoded = Buffer.from(JSON.stringify(ticket)).toString('base64');
  const dashboardUrl = `https://wave-emi-dashboard.vercel.app/?n8n_ticket=${encoded}`;

  results.push({
    json: {
      _source: source,
      dashboard_url: dashboardUrl,
      company: parsed.company || 'Unknown Company',
      amount: parsed.amount || 0,
      type: parsed.type || 'SalaryToMA',
      scenario,
      matrix_complete: matrixComplete,
      matrix_details: matrixResults,
      from_email: from_email,
      original_subject: original_subject,
      to_email: to_email,
      cc_emails: cc_emails,
      email_date: email_date,
      has_attachments: has_attachments,
      attachment_count: attachment_count,
    }
  });
}

return results;
